def decode_cursor(cursor: str | None, *, to_str: bool = True, quoted: bool = True) -> Cursor | None:
    if cursor:
        try:
            cursor = unquote(cursor) if quoted else cursor
            res = b64decode(cursor.encode())
            return res.decode() if to_str else res
        except (binascii.Error, UnicodeDecodeError):
            raise HTTPException(
                status_code=status.HTTP_400_BAD_REQUEST,
                detail="Invalid cursor value",
            ) from None

    return None

def _augment_signature(signature: Signature, *extra: Parameter) -> Signature:
    if not extra:
        return signature

    parameters = list(signature.parameters.values())
    variadic_keyword_params: List[Parameter] = []
    while parameters and parameters[-1].kind is Parameter.VAR_KEYWORD:
        variadic_keyword_params.append(parameters.pop())

    return signature.replace(parameters=[*parameters, *extra, *variadic_keyword_params])

def encode_cursor(
    cursor: Cursor | None,
    *,
    quoted: bool = True,
    encoder: Callable[[bytes], str] = default_encoder,
) -> str | None:
    if cursor:
        cursor = cursor.encode() if isinstance(cursor, str) else cursor
        encoded = encoder(cursor)

        if quoted:
            encoded = quote(encoded)

        return encoded

    return None

